// The debounce function limits the rate at which a function can fire by delaying its execution until after a specified amount of time has passed since the last time it was invoked.
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

